  1→import type {
  2→  SDUIActionDescriptor,
  3→  SDUIActionContext,
  4→  SDUIActionDeps,
  5→  SDUIActionHandler,
  6→  SDUIActionRegistry,
  7→  SDUIActionResult,
  8→  SDUIContext,
  9→} from '../models';
 10→import { SDUI_ANALYTICS_ACTIONS } from '../models';
 11→import { interpolateDeep } from '../utils/interpolation';
 12→
 13→const FAILED_RESULT: SDUIActionResult = { success: false };
 14→
 15→export function createActionRegistry(
 16→  initial?: SDUIActionRegistry,
 17→): SDUIActionRegistry {
 18→  return { ...initial };
 19→}
 20→
 21→export function registerAction(
 22→  registry: SDUIActionRegistry,
 23→  type: string,
 24→  handler: SDUIActionHandler,
 25→): SDUIActionRegistry {
 26→  return { ...registry, [type]: handler };
 27→}
 28→
 29→export function getActionHandler(
 30→  registry: SDUIActionRegistry,
 31→  type: string,
 32→): SDUIActionHandler | undefined {
 33→  return registry[type];
 34→}
 35→
 36→function buildMergedContext(actionContext: SDUIActionContext): SDUIContext {
 37→  return {
 38→    ...actionContext.screen,
 39→    form: actionContext.form as unknown as SDUIContext,
 40→  };
 41→}
 42→
 43→export async function executeAction(
 44→  registry: SDUIActionRegistry,
 45→  descriptor: SDUIActionDescriptor,
 46→  actionContext: SDUIActionContext,
 47→  deps: SDUIActionDeps,
 48→): Promise<SDUIActionResult> {
 49→  const handler = registry[descriptor.type];
 50→  if (!handler) {
 51→    if (__DEV__) {
 52→      console.warn(`[SDUI] Unknown action type: "${descriptor.type}"`);
 53→    }
 54→    return { success: false, error: `Unknown action type: "${descriptor.type}"` };
 55→  }
 56→
 57→  const mergedContext = buildMergedContext(actionContext);
 58→  const interpolatedPayload = descriptor.payload
 59→    ? interpolateDeep(descriptor.payload, mergedContext)
 60→    : undefined;
 61→
 62→  try {
 63→    return await handler(interpolatedPayload, actionContext, deps);
 64→  } catch (err) {
 65→    const message = err instanceof Error ? err.message : String(err);
 66→    if (__DEV__) {
 67→      console.error(`[SDUI] Action "${descriptor.type}" threw:`, message);
 68→    }
 69→    return { success: false, error: message };
 70→  }
 71→}
 72→
 73→export async function executeActions(
 74→  registry: SDUIActionRegistry,
 75→  descriptors: SDUIActionDescriptor[],
 76→  actionContext: SDUIActionContext,
 77→  deps: SDUIActionDeps,
 78→): Promise<SDUIActionResult[]> {
 79→  const results: SDUIActionResult[] = [];
 80→
 81→  const analyticsActions: SDUIActionDescriptor[] = [];
 82→  const primaryActions: SDUIActionDescriptor[] = [];
 83→
 84→  for (const desc of descriptors) {
 85→    if (SDUI_ANALYTICS_ACTIONS.has(desc.type)) {
 86→      analyticsActions.push(desc);
 87→    } else {
 88→      primaryActions.push(desc);
 89→    }
 90→  }
 91→
 92→  for (const desc of primaryActions) {
 93→    const result = await executeAction(registry, desc, actionContext, deps);
 94→    results.push(result);
 95→  }
 96→
 97→  for (const desc of analyticsActions) {
 98→    const result = await executeAction(registry, desc, actionContext, deps);
 99→    results.push(result);
100→  }
101→
102→  return results;
103→}
